import re

def smart_sort(data):
    """
    Sorts a list of strings intelligently, handling numerical and textual patterns.

    Args:
        data: A list of strings to sort.

    Returns:
        A new list containing the sorted strings.
    """

    def try_int(s):
        try:
            return int(s)
        except ValueError:
            return s

    def alphanum_key(s):
        """ Turn a string into a list of string and number chunks.
            "z23a" -> ["z", 23, "a"]
        """
        return [ try_int(c) for c in re.split('([0-9]+)', s) ]

    def month_key(s):
        months = ["January", "February", "March", "April", "May", "June",
                  "July", "August", "September", "October", "November", "December"]
        month_nums = {month: i + 1 for i, month in enumerate(months)}
        parts = s.split()
        nums = []
        for part in parts:
            if part in months:
                nums.append(month_nums[part])
            else:
                try:
                    nums.append(int(part))
                except ValueError:
                    nums.append(part)
        return nums

    def worded_num_key(s):
        worded_nums = {"One": 1, "Two": 2, "Three": 3, "Four": 4, "Five": 5,
                       "Six": 6, "Seven": 7, "Eight": 8, "Nine": 9, "Ten": 10,
                       "Eleven": 11, "Twelve": 12, "Thirteen": 13, "Fourteen": 14,
                       "Fifteen": 15, "Sixteen": 16, "Seventeen": 17, "Eighteen": 18,
                       "Nineteen": 19, "Twenty": 20}
        parts = s.split()
        nums = []
        for part in parts:
            if part in worded_nums:
                nums.append(worded_nums[part])
            else:
                try:
                    nums.append(int(part))
                except ValueError:
                    nums.append(part)
        return nums

    def detect_pattern(data):
        """Detects the most likely sorting pattern."""
        if not data:
            return "alphanumeric"  # Default if data is empty

        has_numbers = any(re.search(r'\d', s) for s in data)
        has_months = any(re.search(r'(January|February|March|April|May|June|July|August|September|October|November|December)', s, re.IGNORECASE) for s in data)
        has_worded_nums = any(re.search(r'(One|Two|Three|Four|Five|Six|Seven|Eight|Nine|Ten|Eleven|Twelve|Thirteen|Fourteen|Fifteen|Sixteen|Seventeen|Eighteen|Nineteen|Twenty)', s, re.IGNORECASE) for s in data)

        if has_numbers:
            if has_months:
                return "month"
            elif has_worded_nums:
                return "worded_num"
            else:
                return "alphanumeric"
        else:
            return "alphabetical"

    pattern = detect_pattern(data)

    if pattern == "alphanumeric":
        return sorted(data, key=alphanum_key)
    elif pattern == "month":
        return sorted(data, key=month_key)
    elif pattern == "worded_num":
        return sorted(data, key=worded_num_key)
    else:
        return sorted(data)

