                        "Nineteen": 19, "Twenty": 20}
        numbers = []
        for word in s.split():
            if word in word_to_num:
                numbers.append(word_to_num[word])
        if numbers:
            return numbers
        return None

    # Attempt different sorting methods
    month_sortable = all(month_key(s) for s in data if month_key(s))
    worded_number_sortable = all(worded_number_key(s) for s in data if worded_number_key(s))
    alphanumeric_sortable = all(re.search(r'\d', s) for s in data if re.search(r'\d', s))

