            "nineteen": 19, "twenty": 20, "thirty": 30, "forty": 40,
            "fifty": 50, "sixty": 60, "seventy": 70, "eighty": 80,
            "ninety": 90
        }

        def convert_word_to_number(s):
            words = s.lower().split()
            total = 0
            current = 0
            for word in words:
                if word in word_to_num:
                    current += word_to_num[word]
                else:
                    return None  # Not a valid worded number
            return current

        try:
            converted_values = [convert_word_to_number(s) for s in strings]
            if all(val is not None for val in converted_values):
                return [s for _, s in sorted(zip(converted_values, strings))]
            else:
                return None
        except:
            return None

