            else:
                return None
        except:
            return None

    def try_partial_numerical_sort(strings):
        def extract_number(s):
            match = re.search(r"(\d+)", s)
            if match:
                return int(match.group(1))
            else:
                return None

        try:
            extracted_numbers = [extract_number(s) for s in strings]
            if all(num is not None for num in extracted_numbers):
                return [s for _, s in sorted(zip(extracted_numbers, strings))]
            else:
                return None
        except:
            return None

