        A new list with the strings sorted according to the detected pattern.
    """

    def try_convert(text):
        """
        Attempts to convert a string to an integer or float.
        Returns the original string if conversion fails.
        """
        try:
            return int(text)
        except ValueError:
            try:
                return float(text)
            except ValueError:
                return text

